"""
MKT Christ Commentary — Nehemiah chapters 5–6
Run: python3 scripts/zc-christ-nehemiah-5-6.py
Verses: ch5×19 + ch6×19 = 38
Ch5: Nehemiah's economic justice intervention — debt relief, servant leadership, "remember me"
Ch6: Enemy plots, false accusation, false prophet, wall completed in 52 days
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "5": {
    "1": "<p>A shadow: 'A great outcry arose from the people and their wives against their fellow Jews.' The economic oppression described in ch. 5 — debt bondage, mortgage foreclosure, child slavery within the covenant community — is the crisis that Nehemiah's jubilee intervention addresses. Jesus opened his public ministry by quoting Isa 61:1-2 (Luke 4:18-19): 'The Spirit of the LORD is upon me, because he has anointed me to proclaim good news to the poor…to proclaim the year of the LORD's favor.' The 'year of favor' is the jubilee — the Levitical institution (Lev 25) that released debts, returned land, and freed slaves every fiftieth year. Nehemiah's intervention in ch. 5 is an ad-hoc jubilee: the outcry of the poor reaches a leader who has both the authority and the will to act on it. Christ's proclamation of jubilee is the ultimate, unrepeatable implementation of what Nehemiah enacted partially and temporarily.</p>",
    "2": "<p>A type: 'Our families are large — sons and daughters. We need grain just to eat and survive.' The food crisis of the post-exilic community — people unable to feed their children — mirrors the situation Jesus addressed in the wilderness feeding (Matt 14:15-21; John 6:1-13). When the crowd had nothing to eat, Jesus did not send them away hungry; he took what was available, blessed it, and fed 5,000. The disciples' complaint ('we have nothing here but five loaves') echoes the people's complaint here ('we have nothing — our children are hungry'); Jesus's response transforms the scarcity. The feeding miracles are more than mere provision — they signify the Messianic banquet of Isaiah 25:6-8 and the abundance of the kingdom where no one goes without.</p>",
    "3": "<p>A type: 'We have pledged our fields, vineyards, and homes to get grain during the famine.' The forced mortgaging of ancestral land evokes two NT resonances. First, Luke 15:14-16: the prodigal son reduced to famine conditions after squandering his inheritance — the parable's arc from loss of land to restoration mirrors Nehemiah's narrative. Second, Matt 13:44: the man who found treasure in a field and sold all he had to buy it — a reversal image: where debt forces the reluctant sale of fields, the kingdom person willingly sells to obtain something more valuable. The ancestral land system of Israel (each family's <em>naḥălāh</em> = inheritance from YHWH) points to the Abrahamic land promise that Christ fulfills not with acreage but with 'the meek shall inherit the earth' (Matt 5:5).</p>",
    "4": "<p>A shadow: 'We have had to borrow money to pay the king's tax on our fields and vineyards.' The tax question resurfaces in Jesus's ministry: 'Is it lawful to pay taxes to Caesar or not?' (Matt 22:15-22; Mark 12:14-17). Jesus's answer — 'render to Caesar what is Caesar's and to God what is God's' — is not an endorsement of Roman taxation but a reframing: human beings bear God's image (<em>eikon</em>) as coins bear Caesar's image; the primary obligation is to God, before whom every political claim is secondary. The post-exilic community's tax burden to Persia (a foreign empire) parallels the first-century community's tax burden to Rome — both contexts involve God's people under foreign authority, waiting for a deeper liberation.</p>",
    "5": "<p>A fulfillment: 'We are the same flesh as our brothers, and our children are like theirs — yet we are forcing our own children into slavery.' The enslavement of Israelite children by Israelite creditors is the covenant's internal contradiction: you belong to YHWH who brought you out of Egypt, yet you are re-enslaving each other. Hebrews 2:14-17 is the definitive response: 'Since the children have flesh and blood, he too shared in their humanity so that by his death he might break the power of him who holds the power of death — that is, the devil — and free those who all their lives were held in slavery by their fear of death… he had to be made like his brothers in every way.' Christ took on the same flesh (<em>ʾāḥîm</em> = brothers, the same word Nehemiah uses) to deliver those enslaved; his redemption addresses not only external slavery but the deepest bondage.</p>",
    "6": "<p>A type: 'I was deeply angry when I heard their cry and their complaint.' Nehemiah's anger at economic injustice within the covenant community is a righteous anger — the same emotion described of Jesus in Mark 3:5 ('he looked around at them with anger, grieved at their hardness of heart') and in the temple cleansing (John 2:13-17). Jesus's anger at those who had turned the house of prayer into a commercial exchange parallels Nehemiah's anger at those who had turned the covenant brotherhood into a commercial relationship. Both angers are directed not at outsiders but at insiders — the covenant community itself — who have allowed economic exploitation to corrupt their common life. Righteous anger in the face of injustice is a property of divine holiness, not a failure of restraint.</p>",
    "7": "<p>A type: 'After deliberating inwardly, I brought a formal charge against the nobles and officials.' Nehemiah's interior deliberation before confronting the oppressors parallels Jesus's deliberate, measured response to injustice. The cleansing of the temple (John 2:15: 'having made a whip of cords, he drove them all out') was not an impulsive act but a considered prophetic intervention. The accusation in Neh 5:7 — 'you are exacting interest from your own people' — echoes the prophetic charges of Amos 8:4-6 and Mic 3:2-3. Jesus himself stands in this prophetic line: confronting exploitation, calling the powerful to account, and demanding that the covenant community embody economic justice as a dimension of covenant faithfulness.</p>",
    "8": "<p>A type: 'We have done everything we could to buy back (<em>qānâ</em>) our Jewish brothers who were sold to foreigners — yet now you are selling your own brothers.' The redemption of enslaved Israelites from foreign masters is the practice that Ezra-Nehemiah communities carried out voluntarily. Paul's statement in Gal 3:13 — 'Christ redeemed (<em>exagorazō</em>) us from the curse of the law by becoming a curse for us' — is the cosmic fulfillment of exactly this pattern: buying back those who had been sold into bondage. The verb <em>qānâ</em> (to buy/acquire/redeem) carries the full weight of the kinsman-redeemer (<em>gōʾēl</em>) theology: the one who has the means and the relationship buys back what has been lost. Christ is the ultimate <em>gōʾēl</em> who buys back humanity from bondage it had sold itself into.</p>",
    "9": "<p>A shadow: 'What you are doing is wrong. Should you not walk in the fear of our God, so that our enemies will not taunt us?' Nehemiah's appeal to fear of God as the foundation for social ethics anticipates Paul's argument in 2 Cor 7:1 ('since we have these promises, let us cleanse ourselves from every defilement…bringing holiness to completion in the fear of God') and Peter's instruction in 1 Pet 2:12 ('conduct yourselves honorably among the Gentiles, so that they may see your honorable deeds'). The community's internal behavior has external apologetic consequences — how God's people treat each other is a witness to the surrounding nations about the character of their God. This principle operates at its highest level in John 13:35: 'By this all people will know that you are my disciples, if you have love for one another.'</p>",
    "10": "<p>A type: 'I and my brothers and my servants have also been lending them money and grain. Let us stop this charging of interest.' Nehemiah's self-implication — 'we too have been doing this' — before calling for reform is the posture of the intercessor who stands with the guilty rather than above them. Jesus embodies this most fully: 'he was numbered with the transgressors' (Isa 53:12; Luke 22:37), taking his stand alongside those under condemnation rather than maintaining a safe distance. The call to stop charging interest also resonates with Luke 6:35: 'lend, expecting nothing in return, and your reward will be great, and you will be sons of the Most High.' The kingdom economy is characterized by generosity without expectation of return — Nehemiah demands it; Jesus embodies and commands it.</p>",
    "11": "<p>A type: 'Restore to them today their fields, vineyards, olive groves, and houses, and the one-percent interest you have been charging them.' The immediate restoration demanded by Nehemiah — 'today' (<em>hayyôm</em>) — is the urgency of kingdom reversal. Zacchaeus's response to Jesus in Luke 19:8 mirrors exactly this dynamic: 'if I have defrauded anyone, I restore it fourfold' — the encounter with Jesus produces immediate, concrete economic restitution. The jubilee principle (Lev 25) mandated the restoration of all ancestral property every fifty years; Jesus's proclamation of the 'year of the LORD's favor' (Luke 4:19) is the jubilee declared in the arrival of the kingdom. Where the jubilee was always in the future, the kingdom brings the jubilee's substance into the present: the captives are freed, the debts released, the fields restored.</p>",
    "12": "<p>A shadow: 'They replied, We will give everything back and demand nothing more. We will do exactly as you say. And I called the priests and made them take an oath to do what they promised.' The oath of restoration sworn before the priests resonates with Heb 6:16-18: human oaths appeal to a higher authority to confirm commitment; YHWH himself swore by himself (because there was no one greater to swear by) in the Abrahamic covenant. The covenant renewal in Nehemiah's administration — sworn and recorded — anticipates the new covenant of Jer 31:31-34, which Christ mediates (Heb 8:6): a covenant not written in stone or sealed by human oath but inscribed by the Spirit on hearts, guaranteed not by human promise but by the faithfulness of the one who cannot lie.</p>",
    "13": "<p>A type: 'I also shook out the fold of my robe and said, May God shake out and empty every man like this who does not keep his promise — from his house and from his property.' The prophetic sign-act of shaking out the garment is performed in Acts 13:51 (Paul and Barnabas shake the dust from their feet against those who rejected the gospel) and Acts 18:6 (Paul shakes out his garments, declaring 'your blood is on your own heads'). The sign declares the severance of responsibility and relationship — those who reject the covenant terms bear their own consequences. Revelation 3:16 uses the related image of spewing the lukewarm from the mouth: rejection by Christ of those who make no decisive commitment. The sign-act does not wish evil but declares the natural consequence of covenant-breaking, and calls the community to witness the seriousness of commitment.</p>",
    "14": "<p>A type: 'Throughout my entire term as governor of Judah — twelve years — I and my brothers did not eat the food allotted to the governor.' Nehemiah's renunciation of his official entitlements is a concrete embodiment of servant leadership that Jesus describes in Mark 10:42-45: 'whoever would be great among you must be your servant…for the Son of Man came not to be served but to serve, and to give his life as a ransom for many.' The governor's allowance was a legal right; Nehemiah voluntarily waived it because the burden on the people was already too heavy. Paul applies this same logic in 1 Cor 9: he had the right to financial support from the churches he planted, but he waived that right to remove any obstacle to the gospel. Nehemiah models the kenotic leadership that Christ embodies absolutely.</p>",
    "15": "<p>A type: 'The governors before me had burdened the people heavily, taking food and wine from them in addition to forty shekels of silver. Even their servants lorded it over the people.' The contrast between the exploiting governors and Nehemiah the servant-leader is Jesus's own contrast in Mark 10:42-45: 'the rulers of the Gentiles lord it over them (<em>katakurieuousin</em>)…it shall not be so among you.' The post-exilic experience of governors who used their position to extract wealth from the vulnerable is the exact pattern Jesus identifies as the worldly model of power — and explicitly rejects as the model for his community. The kingdom inverts the normal power dynamic: the greatest is the servant of all (Mark 9:35), and the model leader is the one who consumes least while contributing most.</p>",
    "16": "<p>A type: 'I also gave myself fully to the work on this wall and did not purchase any land.' Nehemiah's refusal to accumulate land while in office is a renunciation of the governor's opportunity for self-enrichment — the same opportunity that corrupted his predecessors. Phil 2:21 — 'for they all seek their own interests, not those of Jesus Christ' — provides the contrast: Nehemiah is the type of the leader who genuinely subordinates personal interest to the mission. This reaches its ultimate expression in Christ, who 'though he was rich, for your sake became poor, so that you through his poverty might become rich' (2 Cor 8:9). The governor who refused to acquire land prefigures the Lord who 'had nowhere to lay his head' (Matt 8:20), wholly given to the work he was sent to complete.</p>",
    "17": "<p>A type: 'Moreover, I regularly fed 150 Jewish officials at my table, in addition to visitors from the surrounding nations.' Nehemiah's open table — feeding officials and foreign visitors without distinction — resonates with Luke 14:12-14: 'when you give a feast, invite the poor, the crippled, the lame, the blind, and you will be blessed.' Jesus's practice of table fellowship scandalized the religious establishment precisely because he welcomed the excluded (Luke 15:1-2: 'this man receives sinners and eats with them'). The messianic banquet (Isa 25:6-8; Luke 14:15-24; Rev 19:9) is the eschatological fulfillment of the open table: all nations invited, no one turned away, the feast underwritten by the host's own sacrifice rather than the guests' reciprocity.</p>",
    "18": "<p>A shadow: 'Each day my table required one ox, six prime sheep, birds, and generous supplies of wine every ten days. In spite of all this I never claimed the food allowance because the service demanded of this people was already heavy.' The cost Nehemiah bore personally to feed his table without charging it to the community is a type of Christ's provision at no cost to the recipient. John 6:35 — 'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst' — is the promise of the one who feeds freely. The Eucharist is the sacramental enactment of Nehemiah's principle: the host absorbs the cost; the guests receive without payment. 'Come, buy wine and milk without money and without price' (Isa 55:1) is the economy of the messianic feast that Christ inaugurates at the Last Supper.</p>",
    "19": "<p>A fulfillment: 'Remember me with favor, O my God, for everything I have done for this people.' Nehemiah's prayer — <em>zᵉḵōr-lî ʾĕlōhay lᵉṭôḇāh</em>, 'remember me for good' — is the prayer of the faithful servant asking for divine acknowledgment of service rendered. Luke 23:42 presents the most direct NT parallel: the thief on the cross — 'Jesus, remember me when you come into your kingdom' — uses the same petition structure: remember me + the one I appeal to + in your kingdom/favor. Where Nehemiah prays retrospectively (for past service), the thief prays eschatologically (for inclusion in the future kingdom). Both prayers are heard: Nehemiah's memoir testifies that God did remember him; Jesus's response — 'today you will be with me in paradise' — is the definitive divine remembrance, transforming the death-moment into the entry of the remembered into the eternal kingdom.</p>"
  },
  "6": {
    "1": "<p>A type: 'When Sanballat, Tobiah, Geshem, and the rest of our enemies heard that the wall was rebuilt and that no breach was left in it — though at that time I had not yet set the doors in the gates.' The wall complete but the gates not yet set is the moment of maximum enemy anxiety — the defensive perimeter exists but the city is not yet fully secured. John 10:9 — 'I am the door; if anyone enters by me, he will be saved' — is the Christological fulfillment of the gate that guards the city. The enemies attack at precisely the liminal moment between near-completion and full security: similarly, Satan's temptation in the wilderness (Luke 4:1-13) comes between Jesus's baptism (commissioning) and the beginning of his ministry (full entry into work). The adversary always attacks at thresholds.</p>",
    "2": "<p>A type: 'Sanballat and Geshem sent a message: Come, let us meet in one of the villages in the plain of Ono.' The invitation to meet in neutral territory was a trap — Nehemiah perceived it as a plot to harm him (v.2b). The structure parallels the Synoptic temptation: the devil invites Jesus to a place (the pinnacle of the temple, a high mountain) under the appearance of reasonable challenge, when the true intent is to divert him from his mission. John 7:1-11 presents a subtler version: Jesus's brothers invite him to go up to Jerusalem publicly ('show yourself to the world') at the time when the Jewish leaders were seeking to kill him — seemingly reasonable advice that would have delivered him prematurely to his enemies. Nehemiah's refusal — 'I am not able to come down' — is the pattern of the faithful mission-holder who recognizes the friendly invitation as the enemy's tool.</p>",
    "3": "<p>A fulfillment: 'I sent back this reply: I am engaged in an important work and cannot come down. Why should the work stop while I leave it and come down to you?' Nehemiah's answer is one of the OT's most theologically concentrated statements of mission focus: the work itself is the calling, and anything that interrupts it is a threat, however reasonable it appears. Jesus states the same principle in John 9:4 — 'we must work the works of him who sent me while it is day; night is coming, when no one can work' — and in Heb 12:2: 'for the joy set before him he endured the cross, despising the shame, and is seated at the right hand of the throne of God.' The refusal to come down from the cross is the ultimate expression of Nehemiah's principle: the work cannot be abandoned at the enemy's invitation, even at the cost of appearing vulnerable. 'He saved others; he cannot save himself' (Matt 27:42) is the taunt that echoes Sanballat's invitation — come down from your mission and we will honor you.</p>",
    "4": "<p>A shadow: 'Four times they sent the same kind of message, and each time I gave them the same answer.' The persistence of the enemy and the consistency of the response is a pattern throughout Jesus's ministry. Luke 4:13 notes that 'when the devil had finished all the temptation, he departed from him until an opportune time' — the adversary does not give up after a single refusal but waits and returns. The four attempts on Nehemiah mirror the sustained nature of the opposition to Jesus: the Pharisees, the chief priests, the Herodians, and the Sadducees each approach him in succession (Mark 12) with different traps — each time he answers and they depart, but the next challenge immediately follows. Faithfulness under repeated pressure is itself a theological virtue, not merely tactical persistence.</p>",
    "5": "<p>A type: 'A fifth time, Sanballat sent his aide to me with an unsealed letter.' The unsealed letter (unlike official sealed correspondence) was a public document — its contents were visible to anyone who handled it. The accusation it contained was designed for maximum public exposure: read by the courier, potentially by the governors of the province, and by anyone in Jerusalem. The tactic of public accusation to create social pressure before formal charges parallels the Sanhedrin's strategy against Jesus: gathering public testimony (Mark 14:55-59), using it to pressure Pilate (John 19:12: 'if you release him, you are no friend of Caesar'), and relying on public opinion to do the work of conviction. The open letter is the precursor of trial by public opinion.</p>",
    "6": "<p>A type: 'Reports are circulating among the surrounding nations — Geshem confirms this — that you and the Jews are planning to rebel, and that is why you are rebuilding the wall. Furthermore, you intend to become their king.' The false charge against Nehemiah — rebuilding the wall = planning rebellion = claiming kingship — is structurally identical to the charge against Jesus before Pilate: 'We found this man misleading our nation and forbidding us to give tribute to Caesar, and saying that he himself is Christ, a king' (Luke 23:2). Both charges take a real activity (building / teaching) and reframe it as political sedition against Rome/Persia. Both charges are political rather than religious because political charges carry the death penalty. The accusation 'you want to be king' is the lie that both Nehemiah and Jesus must face, and that both answer with the same principled refusal to capitulate.</p>",
    "7": "<p>A type: 'You have even arranged for prophets to announce in Jerusalem, There is a king in Judah! This will soon reach the king. Come and consult with us.' The allegation that prophets had announced Nehemiah as king parallels the accusation that Jesus claimed to be the Messiah/King of the Jews. In both cases, the accusers use the language of kingship as a political weapon. The irony of Nehemiah's situation: he is not claiming to be king, yet the charge is made; Jesus is the king, yet the charges against him are presented as fabrication. John 18:37 — 'you say that I am a king. For this purpose I was born' — is Jesus's paradoxical acknowledgment: he does not deny the kingship but redefines it utterly ('my kingdom is not of this world'). The false charge becomes the unwitting declaration of truth.</p>",
    "8": "<p>A shadow: 'I sent back this reply: None of what you describe has actually happened. You have fabricated the whole thing.' Nehemiah's simple denial — <em>lōʾ-niḥyû haddᵉḇārîm hāʾēlleh</em>, 'these things are not so' — is the answer of someone with nothing to hide. Jesus's response to the high priest at his trial (John 18:20-21) is similarly direct: 'I have spoken openly to the world; I have said nothing in secret…why do you ask me? Ask those who have heard me.' Both Nehemiah and Jesus answer false charges not with elaborate defense but with simple truth and an appeal to the public record. The contrast with the false witnesses (Mark 14:59: 'their testimony did not agree') is telling: fabrications are internally inconsistent; the truth has no need of elaborate construction.</p>",
    "9": "<p>A fulfillment: 'They were all trying to frighten us, thinking our hands would go limp and the work would stop. So I prayed: Strengthen my hands.' The prayer <em>ḥazzēq ʾet-yāḏāy</em> (strengthen my hands) is itself a fulfillment of Isa 35:3-4: 'Strengthen the weak hands, and make firm the feeble knees. Say to those who have an anxious heart, Be strong; fear not! Behold, your God will come with vengeance.' Heb 12:12-13 applies this Isaiah passage directly to the new covenant community: 'lift your drooping hands and strengthen your weak knees, and make straight paths for your feet.' The prayer for strengthened hands is the prayer of the person who recognizes that faithfulness in the face of intimidation is not a human achievement but a divine gift. Christ himself in Gethsemane (Luke 22:43) receives the strengthening of an angel — the Son of God, praying for the hands to complete what was set before him.</p>",
    "10": "<p>A type: 'I went to the house of Shemaiah, who was homebound. He said, Let us meet together in the house of God, inside the temple, and let us close the temple doors, because they are coming to kill you — by night they are coming to kill you.' The false counsel — hide in the temple for safety — is advice that misuses sacred space to protect the threatened leader. The temptation of Jesus in Matt 4:5-6 presents the exact inverse: the devil takes Jesus to the pinnacle of the temple and urges him to throw himself down, invoking divine protection. Both are false uses of the temple as a safety mechanism. Jesus's response — 'you shall not put the Lord your God to the test' — is the answer Nehemiah gives implicitly: he would not use the sacred space to evade the mission. Fidelity means staying on the wall, not hiding in the sanctuary.</p>",
    "11": "<p>A fulfillment: 'I replied, Should a man in my position run away? And who, being in my position, would enter the temple to save his life? I will not go in.' Nehemiah's refusal to flee or hide is the OT type of Christ's deliberate choice not to avoid the cross. Isaiah 50:7 — 'I set my face like flint' — is the prophetic anticipation; Luke 9:51 — 'he set his face to go to Jerusalem' — is the fulfillment. John 10:11-13 provides the theological contrast: the good shepherd does not flee when the wolf comes; the hired hand flees and leaves the flock. Nehemiah refusing to run away from his enemies embodies the good shepherd pattern: the leader who does not prioritize personal safety above the community's welfare. Christ's refusal to 'come down from the cross' (Matt 27:40, 42) is the ultimate expression of this faithfulness — he could have escaped; he chose not to.</p>",
    "12": "<p>A shadow: 'I understood then that God had not sent him — he had given this prophecy against me because Tobiah and Sanballat had hired him. He was hired to frighten me into acting this way — to make me sin, so they could damage my reputation and discredit me.' Nehemiah's discernment — recognizing a true prophet from a false one based on the fruit of the counsel — is the practical implementation of Jesus's teaching in Matt 7:15-20: 'beware of false prophets…you will recognize them by their fruits.' The false prophet's counsel would have made Nehemiah sin (entering the temple as a layman would be a sin) — a counsel designed to corrupt. Jesus faces the same pattern: the Pharisees and Herodians attempt to trap him with questions designed to make him sin (Matt 22:15-22). The discernment of false prophecy is a spiritual discipline that Christ himself exercised and that he equips his community to exercise (1 John 4:1).</p>",
    "13": "<p>A type: 'He had been hired to frighten me into acting this way — to make me sin, so they could damage my reputation and discredit me.' The conspiracy to entrap Nehemiah through false prophecy is a direct type of the conspiracy against Jesus at his trial: 'the chief priests and the whole council were seeking false testimony against Jesus that they might put him to death, but they found none, though many false witnesses came forward' (Matt 26:59-60). Both conspiracies used intermediaries (hired prophet / hired false witnesses), both aimed to compromise the integrity of the target, and both failed to produce the desired outcome. The NT pattern is exact: Judas was 'paid' (Matt 26:15) to betray Jesus; Shemaiah was 'hired' (Neh 6:12-13) to entrap Nehemiah. The payment for betrayal is a recurrent motif marking the enemy's ultimate reliance on purchased rather than principled opposition.</p>",
    "14": "<p>A shadow: 'My God, remember what Tobiah and Sanballat have done — and also the prophetess Noadiah and the other prophets who have been trying to intimidate me.' The imprecatory prayer — calling on God to act as divine judge against those who used prophetic office to harm — parallels Rev 6:10 ('how long, O Lord, holy and true, before you will judge and avenge our blood on those who dwell on the earth?') and 2 Tim 4:14 ('Alexander the coppersmith did me great harm; the Lord will repay him according to his deeds'). The NT is not squeamish about calling for divine justice against those who actively oppose and corrupt the work of God. Both Paul and John the Revelator make the same appeal as Nehemiah — not personal vengeance but the application of divine justice. The judge of all the earth will do right (Gen 18:25).</p>",
    "15": "<p>A fulfillment: 'The wall was completed on the twenty-fifth day of Elul, in fifty-two days.' The wall's completion in 52 days is the climax of the Nehemiah narrative. Jesus's declaration from the cross — <em>tetelestai</em>, 'it is finished' (John 19:30) — is the ultimate completion formula: the work assigned from before the foundation of the world, executed in 33 years, declared finished at the moment of apparent defeat. John 17:4 — 'I have brought you glory on earth by finishing (<em>teleioō</em>) the work you gave me to do' — is the high-priestly prayer's completion claim, anticipating the cross. Nehemiah's 52 days of wall-building under opposition ends with the wall done; Christ's earthly mission under the maximum opposition of death itself ends with 'finished' — both completions are, in their respective contexts, impossible achievements that demonstrate divine faithfulness.</p>",
    "16": "<p>A fulfillment: 'When all our enemies heard of it and all the surrounding nations saw it, their confidence collapsed, for they recognized that this work had been done with the help of our God.' The collapse of the enemies' confidence at the completion of the work fulfills Ps 126:2-3: 'then it was said among the nations, The LORD has done great things for them.' Phil 1:28 applies the same dynamic to the NT community: not being frightened 'in anything by your opponents — this is a clear sign to them of their destruction, but of your salvation, and that from God.' The enemies' recognition that the impossible was accomplished — despite their best opposition — functions as a forensic judgment: the work's completion proves who was on the right side. The resurrection of Christ is the supreme instance: the sealed tomb, the Roman guard, and the rolling-back of the stone are all overcome; and the empty tomb is the divine verdict on the cross.</p>",
    "17": "<p>A type: 'Meanwhile, during this period, the nobles of Judah were sending many letters to Tobiah, and Tobiah's replies were reaching them.' The network of insiders in Jerusalem secretly communicating with Nehemiah's primary enemy is the structural parallel of the Sanhedrin's intelligence network against Jesus. John 11:57 — 'the chief priests and the Pharisees had given orders that if anyone knew where he was, he should let them know' — is exactly the Tobiah-network pattern: insiders reporting on the movements and words of the threatened leader to those who seek his harm. Judas, the insider disciple, is the concentrated figure of what the Judean nobles represent collectively: people within the covenant community who chose alliance with the opposing power over loyalty to the mission.</p>",
    "18": "<p>A shadow: 'Many in Judah were sworn to him by oath: he was the son-in-law of Shecaniah son of Arah, and his son Jehohanan had married the daughter of Meshullam son of Berechiah.' The family alliances that bound the Judean nobles to Tobiah were the mechanism of the betrayal — marriage ties and sworn loyalties created obligations that superseded covenant fidelity. John 7:13 — 'no one spoke openly about him for fear of the Jewish leaders' — describes the same social pressure: people who were privately sympathetic but publicly silent due to institutional loyalties. Luke 22:4-5 — Judas going to the chief priests and agreeing to betray Jesus for money — shows the alliance structure: the insider's private defection enables what the external opposition could not achieve. The betrayal from within is always more damaging than the attack from without.</p>",
    "19": "<p>A type: 'They would speak of his good deeds to me and report my responses back to him. And Tobiah kept sending letters to intimidate me.' The double intelligence operation — Tobiah's advocates reporting favorably about him to Nehemiah while reporting Nehemiah's words back to Tobiah — is the pattern of the hostile informer who moves freely through both camps. Luke 20:20 — 'so they watched him and sent spies who pretended to be righteous, in order to trap him in what he said' — is the NT fulfillment: the Pharisees sent agents who appeared sympathetic to gather intelligence for the prosecution. The same tactic used against Nehemiah — friendly information-gathering that feeds hostile intelligence — was used against Jesus throughout his ministry. Yet both Nehemiah and Jesus continued their work openly, because the one whose speech and action are consistent has nothing to hide from informers.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'nehemiah')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', 'nehemiah', c)
    total = sum(len(vs) for vs in CHRIST.values())
    print(f'nehemiah mkt-christ: {total} verses written (ch5-6)')

if __name__ == '__main__':
    main()
